Here's how to handle each scenario with modern MSTest (3.9+/3.10+):

```csharp
using Microsoft.VisualStudio.TestTools.UnitTesting;

[TestClass]
public sealed class PlatformAndEnvironmentTests
{
    private readonly TestContext _testContext;
    private string? _tempFile;

    public PlatformAndEnvironmentTests(TestContext testContext)
    {
        _testContext = testContext;
    }

    // 1. Windows-only: skipped on Linux/macOS
    [TestMethod]
    [OSCondition(OperatingSystems.Windows)]
    public void Registry_ReadsExpectedValue()
    {
        var value = Microsoft.Win32.Registry.GetValue(
            @"HKEY_LOCAL_MACHINE\SOFTWARE\Microsoft\Windows NT\CurrentVersion",
            "ProductName", null);
        Assert.IsNotNull(value);
    }

    // 2. Skip in CI (requires local GPU)
    [TestMethod]
    [CICondition(ConditionMode.Exclude)]
    public void GpuCompute_ProducesCorrectOutput()
    {
        // Only runs locally, skipped in CI environments
        var result = GpuRenderer.Render(frame: 1);
        Assert.IsNotNull(result);
    }

    // 3. Flaky external API — retry up to 3 times
    [TestMethod]
    [Retry(3)]
    [Timeout(10000)]
    public async Task WeatherApi_ReturnsData()
    {
        var response = await new HttpClient()
            .GetAsync("https://api.weather.example/current",
                      _testContext.CancellationToken);
        Assert.IsTrue(response.IsSuccessStatusCode);
    }

    // 4. Cleanup temp files even on failure via [TestCleanup]
    [TestMethod]
    public void Export_CreatesValidFile()
    {
        _tempFile = Path.GetTempFileName();
        File.WriteAllText(_tempFile, "test data");

        var result = FileProcessor.Validate(_tempFile);
        Assert.IsTrue(result);
    }

    [TestCleanup]
    public void Cleanup()
    {
        // Runs after every test, even if it fails or throws
        if (_tempFile is not null && File.Exists(_tempFile))
        {
            File.Delete(_tempFile);
        }
    }
}
```

**Summary of attributes:**

| Scenario | Attribute | Min Version |
|----------|-----------|-------------|
| OS-specific | `[OSCondition(OperatingSystems.Windows)]` | 3.10+ |
| Skip in CI | `[CICondition(ConditionMode.Exclude)]` | 3.10+ |
| Flaky/retry | `[Retry(3)]` | 3.9+ |
| Cleanup on failure | `[TestCleanup]` method | All versions |

**Key notes:**
- `[Retry]` should only be used for genuinely flaky external dependencies, not to mask race conditions.
- `[TestCleanup]` always runs (even on failure/exception), making it ideal for temp file deletion.
- Combine `[Timeout]` with `TestContext.CancellationToken` for async tests to ensure proper cancellation.
